// ============================================================================
// CODE 3 - EXTRACTION ET COMBINAISON DES VALEURS CATEGORIE ET PREAVIS
// ============================================================================

const items = $input.all();

// Initialiser les variables pour stocker les valeurs
let categorie = "non définie";
let preavis = "non définie";

// Parcourir tous les items pour extraire CATEGORIE et PREAVIS
items.forEach(item => {
  const lanchp = item.json["$resources"][0].LANCHP;
  const lanmes = item.json["$resources"][0].LANMES;
  const lannum = item.json["$resources"][0].LANNUM;

  if (lanchp === 6262) {
    // Menu 6262 → CATEGORIE
    categorie = (lannum === 0 || lannum === null) ? "non définie" : lanmes;

  } else if (lanchp === 6263) {
    // Menu 6263 → PREAVIS
    preavis = (lanmes === "1234" || lannum === 1234 ) ? "non définie" : lanmes;
  }
});

// Retourner UN SEUL item avec les deux valeurs combinées
return [
  {
    json: {
      CATEGORIE: categorie,
      PREAVIS: preavis
    }
  }
];

// ============================================================================
// CODE - MAPPING DES DONNÉES SAGE X3 AVEC CONVERSION DES CODES
// ============================================================================

// Récupérer les données du HTTP Request (XDEMISSION)
const xdemissionData = $node["récupérer donnes selon numéro démission"].json;

// Récupérer les données de Code3 (CATEGORIE et PREAVIS)
const code3Data = $input.first().json;

const mapping = {
  XNUM: "no_dossier",
  XSAL: "code_salarie",
  XDATENT: "date_entree",
  XDATDEM: "date_demission",
  XFLGLEG: "signature_legalisee",
  XTYPSAL: "categorie_csp",
  XDURPR: "duree_preavis",
  XDATPR: "date_fin_preavis",
  XRMPINT: "remplacant_interim",
  XPVVAL: "validation_pv_passation",
  XMATOK: "restitution_materiel",
  XDRKLNK: "lien_recrutement",
  XFLGREMP: "flag_remplacement",
  XPOSTE: "poste",
  XMOTIF: "motif_demission",
  XDATACC: "date_preavis_accorde"
};

// Tables de conversion pour duree_preavis (en jours)
const dureePreavisMapping = {
  "CE": 0,
  "non définie": 0,
  "8 jours": 8,
  "1 mois": 30,
  "2 mois": 60,
  "3 mois": 90
};

const output = {};

// Méta-informations
output.source = "SageX3";

// Mapper les champs depuis XDEMISSION
for (const key in xdemissionData) {
  if (mapping[key]) {
    let value = xdemissionData[key];

    // Conversion spéciale pour XTYPSAL (catégorie CSP)
    if (key === "XTYPSAL") {
      value = code3Data.CATEGORIE;
    }

    // Conversion spéciale pour XDURPR (durée de préavis)
    if (key === "XDURPR") {
      const preavisText = code3Data.PREAVIS;
      value = dureePreavisMapping[preavisText] !== undefined 
        ? dureePreavisMapping[preavisText] 
        : 0;
    }

    output[mapping[key]] = value;
  }
}

// Ajouter les valeurs textuelles pour référence
output.categorie_csp_text = code3Data.CATEGORIE;
output.duree_preavis_text = code3Data.PREAVIS;

return [{ json: output }];

