function formatDate(dateString) {
  if (!dateString) return 'Non spécifiée';
  const date = new Date(dateString);
  if (isNaN(date.getTime())) return dateString;

  const day = String(date.getDate()).padStart(2, '0');
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const year = date.getFullYear();

  return `${day}/${month}/${year}`;
}

function calculateEndDate(startDate, daysToAdd) {
  if (!startDate || !daysToAdd) return null;

  const date = new Date(startDate);
  date.setDate(date.getDate() + parseInt(daysToAdd));

  return date.toISOString().split('T')[0];
}

function getLanguage(langCode) {
  if (!langCode || langCode.trim() === '') return 'FRA';

  const lang = langCode.toUpperCase().trim();
  return ['FRA', 'ENG', 'ARA'].includes(lang) ? lang : 'FRA';
}

function replaceVariables(template, data) {
  let result = template;

  for (const [key, value] of Object.entries(data)) {
    const placeholder = new RegExp(`{{${key}}}`, 'g');
    result = result.replace(placeholder, value || '');
  }

  return result;
}

